#!/bin/sh
set -eu

fail() {
    printf 'FAIL: %s\n' "$1" >&2
    exit 1
}

require_file() {
    [ -s "$1" ] || fail "missing or empty file: $1"
}

require_text() {
    file="$1"
    pattern="$2"
    label="$3"
    grep -Fq -- "$pattern" "$file" || fail "$label missing in $file"
}

reject_text() {
    pattern="$1"
    label="$2"
    if grep -RInE "$pattern" README.md README.ko.md agents docs templates examples 2>/dev/null; then
        fail "$label"
    fi
}

