require_file scripts/validate-all.sh
require_file Makefile
require_file .github/workflows/validate.yml

if grep -nE 'EPUB로 만들어|출판|패키징|프랜차이즈|작품|권|어투|장면|설정|사용자|검증' README.md; then
    fail "Korean prose remains in English README.md"
fi

if grep -nE '^#{1,3} .*\([A-Za-z][A-Za-z /&-]*\)' README.ko.md; then
    fail "English parenthetical heading remains in Korean README.ko.md"
fi

for file in agents/*.md; do
    first_line="$(sed -n '1p' "$file")"
    [ "$first_line" = "---" ] || fail "agent frontmatter delimiter missing: $file"
    require_text "$file" "permission:" "permission block"
done

